using System;
using System.Data.SqlClient;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;

namespace ReportingApi
{
    public static class ReportingFunction
    {
        [FunctionName("ReportingFunction")]
        public static IActionResult Run(
            [HttpTrigger(AuthorizationLevel.Function, "get", Route = null)] HttpRequestData req,
            FunctionContext context)
        {
            string dbName = Environment.GetEnvironmentVariable("DB_NAME");
            string dbUser = Environment.GetEnvironmentVariable("DB_USER");
            string dbPassword = Environment.GetEnvironmentVariable("DB_PASSWORD");

            var query = GetQuery(req);

            try
            {
                using (var conn = new SqlConnection($"Server=tcp:{dbName}.database.windows.net,1433;Database={dbName};User ID={dbUser};Password={dbPassword};Encrypt=True;TrustServerCertificate=False;Connection Timeout=30"))
                {
                    conn.Open();

                    var cmd = new SqlCommand(query, conn);

                    using (var reader = cmd.ExecuteReader())
                    {
                        var results = new List<ReportResult>();

                        while (reader.Read())
                        {
                            results.Add(new ReportResult
                            {
                                Id = reader["id"].ToString(),
                                Name = reader["name"].ToString()
                            });
                        }

                        return new OkObjectResult(results);
                    }
                }
            }
            catch (Exception ex)
            {
                return new StatusCodeResult(StatusCodes.Status500InternalServerError);
            }
        }

        private static string GetQuery(HttpRequestData req)
        {
            var query = "SELECT * FROM reports";

            if (req.Query.ContainsKey("filter"))
            {
                query += $" WHERE {req.Query["filter"]}";
            }

            if (req.Query.ContainsKey("sortby") && req.Query.ContainsKey("orderby"))
            {
                query += $" ORDER BY {req.Query["sortby"]} {req.Query["orderby"]}";
            }

            return query;
        }
